//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagecognitoidentityimport("strings""testing""github.com/aws/aws-sdk-go/service/cognitoidentity")funcTestValidIdentityPoolName(t*testing.T){t.Parallel()validValues:=[]string{"123","123","foo","foobar","foo_bar","1foo2bar3","foo-bar_123","foo-bar",}for_,s:=rangevalidValues{_,errors:=validIdentityPoolName(s,"identity_pool_name")iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoIdentityPoolName:%v",s,errors)}}invalidValues:=[]string{"foo*","foo:bar","foo&bar","foo1^bar2",}for_,s:=rangeinvalidValues{_,errors:=validIdentityPoolName(s,"identity_pool_name")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoIdentityPoolName:%v",s,errors)}}}funcTestValidIdentityProvidersClientID(t*testing.T){t.Parallel()validValues:=[]string{"7lhlkkfbfb4q5kpp90urffao","12345678","foo_123",strings.Repeat("W",128),}for_,s:=rangevalidValues{_,errors:=validIdentityProvidersClientID(s,"client_id")iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoIdentityProviderClientID:%v",s,errors)}}invalidValues:=[]string{"",strings.Repeat("W",129),//>128"foo-bar","foo:bar","foo;bar",}for_,s:=rangeinvalidValues{_,errors:=validIdentityProvidersClientID(s,"client_id")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoIdentityProviderClientID:%v",s,errors)}}}funcTestValidIdentityProvidersProviderName(t*testing.T){t.Parallel()validValues:=[]string{"foo","7346241598935552","foo_bar","foo:bar","foo/bar","foo-bar","cognito-idp.us-east-1.amazonaws.com/us-east-1_Zr231apJu",//lintignore:AWSAT003strings.Repeat("W",128),}for_,s:=rangevalidValues{_,errors:=validIdentityProvidersProviderName(s,"provider_name")iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoIdentityProviderName:%v",s,errors)}}invalidValues:=[]string{"",strings.Repeat("W",129),//>128"foo;bar_baz","foobar,foobaz","foobar=foobaz",}for_,s:=rangeinvalidValues{_,errors:=validIdentityProvidersProviderName(s,"provider_name")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoIdentityProviderName:%v",s,errors)}}}funcTestValidProviderDeveloperName(t*testing.T){t.Parallel()validValues:=[]string{"1","foo","1.2","foo1-bar2-baz3","foo_bar",}for_,s:=rangevalidValues{_,errors:=validProviderDeveloperName(s,"developer_provider_name")iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoProviderDeveloperName:%v",s,errors)}}invalidValues:=[]string{"foo!","foo:bar","foo/bar","foo;bar",}for_,s:=rangeinvalidValues{_,errors:=validProviderDeveloperName(s,"developer_provider_name")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoProviderDeveloperName:%v",s,errors)}}}funcTestValidRoleMappingsAmbiguousRoleResolutionAgainstType(t*testing.T){t.Parallel()cases:=[]struct{AmbiguousRoleResolutioninterface{}TypestringErrCountint}{{AmbiguousRoleResolution:nil,Type:cognitoidentity.RoleMappingTypeToken,ErrCount:1,},{AmbiguousRoleResolution:"foo",Type:cognitoidentity.RoleMappingTypeToken,ErrCount:0,//0asitshouldbedefined,thevalueisn'tvalidatedhere},{AmbiguousRoleResolution:cognitoidentity.AmbiguousRoleResolutionTypeAuthenticatedRole,Type:cognitoidentity.RoleMappingTypeToken,ErrCount:0,},{AmbiguousRoleResolution:cognitoidentity.AmbiguousRoleResolutionTypeDeny,Type:cognitoidentity.RoleMappingTypeToken,ErrCount:0,},}for_,tc:=rangecases{m:=make(map[string]interface{})//Reproducingtheundefinedambiguous_role_resolutioniftc.AmbiguousRoleResolution!=nil{m["ambiguous_role_resolution"]=tc.AmbiguousRoleResolution}m["type"]=tc.Typeerrors:=validRoleMappingsAmbiguousRoleResolutionAgainstType(m)iflen(errors)!=tc.ErrCount{t.Fatalf("CognitoRoleMappingsvalidationfailed:%v,expectederrcount%d,got%d,forconfig%#v",errors,tc.ErrCount,len(errors),m)}}}funcTestValidRoleMappingsRulesConfiguration(t*testing.T){t.Parallel()cases:=[]struct{MappingRule[]interface{}TypeErrCountint}{{MappingRule:nil,Type:ingTypeRules,ErrCount:1,},{MappingRule:[]interface{}{map[string]interface{}{"Claim":"isAdmin","MatchType":"Equals","RoleARN":"arn:foo","Value":"paid",},},Type:cognitoidentity.RoleMappingTypeRules,ErrCount:0,},{MappingRule:[]interface{}{map[string]interface{}{"Claim":"isAdmin","MatchType":"Equals","RoleARN":"arn:foo","Value":"paid",},},Type:cognitoidentity.RoleMappingTypeToken,ErrCount:1,},{MappingRule:nil,Type:ingTypeToken,ErrCount:0,},}for_,tc:=rangecases{m:=make(map[string]interface{})//Reproducingtheundefinedmapping_ruleiftc.MappingRule!=nil{m["mapping_rule"]=tc.MappingRule}m["type"]=tc.Typeerrors:=validRoleMappingsRulesConfiguration(m)iflen(errors)!=tc.ErrCount{t.Fatalf("CognitoRoleMappingsvalidationfailed:%v,expectederrcount%d,got%d,forconfig%#v",errors,tc.ErrCount,len(errors),m)}}}funcTestValidRoles(t*testing.T){t.Parallel()validValues:=[]map[string]interface{}{{"authenticated":"hoge"},{"unauthenticated":"hoge"},{"authenticated":"hoge","unauthenticated":"hoge"},}for_,s:=rangevalidValues{errors:=validRoles(s)iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoRoles:%v",s,errors)}}invalidValues:=[]map[string]interface{}{{},{"invalid":"hoge"},}for_,s:=rangeinvalidValues{errors:=validRoles(s)iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoRoles:%v",s,errors)}}}funcTestValidSupportedLoginProviders(t*testing.T){t.Parallel()validValues:=[]string{"foo","7346241598935552","123456789012.apps.googleusercontent.com",//nosemgrep:ci.domain-names"foo_bar","foo;bar","foo/bar","foo-bar","xvz1evFS4wEEPTGEFPHBog;kAcSOqF21Fu85e7zjz7ZN2U4ZRhfV3WpwPAoE3Z7kBw",strings.Repeat("W",128),}for_,s:=rangevalidValues{_,errors:=validSupportedLoginProviders(s,"supported_login_providers")iflen(errors)>0{t.Fatalf("%qshouldbeavalidCognitoSupportedLoginProviders:%v",s,errors)}}invalidValues:=[]string{"",strings.Repeat("W",129),//>128"foo:bar_baz","foobar,foobaz","foobar=foobaz",}for_,s:=rangeinvalidValues{_,errors:=validSupportedLoginProviders(s,"supported_login_providers")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidCognitoSupportedLoginProviders:%v",s,errors)}}}